"use client";

import React, { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { LucideFilePlus, LucideTrash2 } from "lucide-react";
import axios from "axios";
import toast from "react-hot-toast";
import moment from "moment";

// 1. Define Interfaces for Type Safety
interface ResumeData {
  id: string;
  title: string;
  updatedAt: string;
  thumbnailLink?: string;
  completion?: number;
  profileInfo?: {
    fullName: string;
    designation: string;
    summary: string;
  };
  contactInfo?: {
    email: string;
    phone: string;
  };
  // Add other sections as needed
}

// Components - Ensure these are typed as React.FC or similar
import DashboardLayout from "@/app/components/DashboardLayout";
import Modal from "@/app/components/Modal";
import CreateResumeForm from "@/app/components/CreateResumeForm";
import { ResumeSummaryCard } from "@/app/components/Cards";

const Dashboard: React.FC = () => {
  const router = useRouter();

  // 2. Explicitly type your State hooks
  const [openCreateModal, setOpenCreateModal] = useState<boolean>(false);
  const [allResumes, setAllResumes] = useState<ResumeData[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [resumeToDelete, setResumeToDelete] = useState<string | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // 3. Type the parameter and return value of the logic functions
  const calculateCompletion = (resume: ResumeData): number => {
    let completedFields = 0;
    const totalFields = 5; // Base fields for Profile + Contact

    if (resume.profileInfo?.fullName) completedFields++;
    if (resume.profileInfo?.designation) completedFields++;
    if (resume.profileInfo?.summary) completedFields++;
    if (resume.contactInfo?.email) completedFields++;
    if (resume.contactInfo?.phone) completedFields++;

    return totalFields > 0
      ? Math.round((completedFields / totalFields) * 100)
      : 0;
  };

  const fetchAllResumes = async () => {
    setLoading(true);
    setError(null);
    try {
        // 1. Get the token (same way we do in UserContext)
        const token = localStorage.getItem('token');

        // 2. Use fetch with the Authorization header
        const response = await fetch("/api/resumes", {
            method: "GET",
            headers: {
                "Authorization": `Bearer ${token}`,
                "Content-Type": "application/json",
            },
        });

        if (!response.ok) {
            // If status is 400 or 401, this will catch it
            const errorData = await response.json();
            throw new Error(errorData.message || "Failed to fetch resumes");
        }

        const data: ResumeData[] = await response.json();

        const resumeWithCompletion = data.map((resume: ResumeData) => ({
            ...resume,
            completion: calculateCompletion(resume),
        }));

        setAllResumes(resumeWithCompletion);
    } catch (err: any) {
        console.error("Error fetching resumes:", err);
        setError(err.message);
    } finally {
        setLoading(false);
    }
};

  const handleDeleteResume = async (): Promise<void> => {
    if (!resumeToDelete) return;
    try {
      await axios.delete(`/api/resumes/${resumeToDelete}`);
      toast.success("Resume deleted");
      fetchAllResumes();
    } catch (error: any) {
      toast.error("Failed to delete");
    } finally {
      setResumeToDelete(null);
      setShowDeleteConfirm(false);
    }
  };

  return (
    <DashboardLayout activeMenu="dashboard">
      <div className="max-w-7xl mx-auto p-6">
        <div className="flex justify-between items-center mb-8">
          <div>
            <h1 className="text-3xl font-bold text-white">My Resumes</h1>
            <p className="text-gray-400">
              {allResumes.length > 0
                ? `You have ${allResumes.length} resumes`
                : `Start building your career`}
            </p>
          </div>
          <button
            onClick={() => setOpenCreateModal(true)}
            className="flex items-center gap-2 bg-violet-600 hover:bg-violet-700 text-white px-6 py-2 rounded-lg transition"
          >
            Create Now <LucideFilePlus size={18} />
          </button>
        </div>

        {loading ? (
          <div className="flex justify-center py-20">
            <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-violet-500"></div>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-4 gap-6">
            <div
              onClick={() => setOpenCreateModal(true)}
              className="border-2 border-dashed border-gray-700 rounded-xl flex flex-col items-center justify-center p-10 cursor-pointer hover:border-violet-500 transition group"
            >
              <LucideFilePlus
                size={40}
                className="text-gray-500 group-hover:text-violet-500 mb-2"
              />
              <p className="text-gray-400 group-hover:text-violet-500 font-medium">
                New Resume
              </p>
            </div>

            {allResumes.map((resume) => (
              <ResumeSummaryCard
                key={resume.id}
                imgUrl={resume.thumbnailLink || ""}
                title={resume.title}
                updatedAt={resume.updatedAt}
                completion={resume.completion || 0}
                onSelect={() => router.push(`/editor/${resume.id}`)}
                onDelete={() => {
                  setResumeToDelete(resume.id);
                  setShowDeleteConfirm(true);
                }}
              />
            ))}
          </div>
        )}
      </div>

      <Modal
        isOpen={openCreateModal}
        onClose={() => setOpenCreateModal(false)}
        title="Create New Resume" // Added this
        hideHeader={false} // Added this
        showActionBtn={false}
        actionBtnText = "Submit"
      >
        <CreateResumeForm
          onSuccess={() => {
            setOpenCreateModal(false);
            fetchAllResumes();
          }}
        />
      </Modal>
    </DashboardLayout>
  );
};

export default Dashboard;

"use client"; // Required for hooks like useState/useContext in Next.js

import React, { useState, useContext, useEffect } from 'react';
import { useRouter } from 'next/navigation'; // Correct Next.js router
import Link from 'next/link'; // For optimized footer links
import { landingPageStyles } from '@/src/assets/dummystyle';
import { Download, LayoutTemplate, Menu, X, Zap, ArrowRight } from 'lucide-react';
import { useUser } from '@/src/context/UserContext'
import { ProfileInCard } from '../components/Cards';
import Modal from '../components/Modal';
import Login from '../components/Login';
import Signup from '../components/Signup';

const LandingPage = () => {
    const { user } = useUser();
    const router = useRouter();
    
    const [openAuthModel, setOpenAuthModel] = useState(false);
    const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
    const [currentPage, setCurrentPage] = useState("login");

    // Close mobile menu if window is resized to desktop
    useEffect(() => {
        const handleResize = () => {
            if (window.innerWidth >= 768) setMobileMenuOpen(false);
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const handleCTA = () => {
        if (!user) {
            setOpenAuthModel(true);
        } else {
            router.push('/dashboard'); // Faster Next.js transition
        }
    };

    return (
        <div className={landingPageStyles.container}>
            {/* Header */}
            <header className={landingPageStyles.header}>
                <div className={landingPageStyles.headerContainer}>
                    <div className={landingPageStyles.logoContainer} onClick={() => router.push('/')}>
                        <div className={landingPageStyles.logoIcon}>
                            <LayoutTemplate className={landingPageStyles.logoIconInner}/>
                        </div>
                        <span className={landingPageStyles.logoText}>ResumeXpert</span>
                    </div>

                    {/* MOBILE MENU TOGGLE */}
                    <button className={landingPageStyles.mobileMenuButton}
                        onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
                        {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
                    </button>

                    {/* DESKTOP NAVIGATION */}
                    <div className='hidden md:flex items-center'>
                        {user ? (
                            <ProfileInCard />
                        ) : (
                            <button className={landingPageStyles.desktopAuthButton} onClick={() => setOpenAuthModel(true)}>
                                <div className={landingPageStyles.desktopAuthButtonOverlay}></div>
                                <span className={landingPageStyles.desktopAuthButtonText}>Get Started</span>
                            </button>
                        )}
                    </div>
                </div>

                {/* MOBILE DRAWER */}
                {mobileMenuOpen && (
                    <div className={landingPageStyles.mobileMenu}>
                        <div className={landingPageStyles.mobileMenuContainer}>
                            {user ? (
                                <div className={landingPageStyles.mobileUserInfo}>
                                    <button className={landingPageStyles.mobileDashboardButton}
                                        onClick={() => {
                                            router.push('/dashboard');
                                            setMobileMenuOpen(false);
                                        }}>
                                        Go to Dashboard
                                    </button>
                                </div>
                            ) : (
                                <button className={landingPageStyles.mobileAuthButton}
                                    onClick={() => {
                                        setOpenAuthModel(true);
                                        setMobileMenuOpen(false);
                                    }}>
                                    Get Started
                                </button>
                            )}
                        </div>
                    </div>
                )}
            </header>

            <main className={landingPageStyles.main}>
                {/* HERO SECTION - Keep your SVG and Grid as is, they are great */}
                {/* ... existing hero code ... */}
                
                {/* CTA Button Fix: Ensure z-index is correct so clicks register */}
                <button className={landingPageStyles.primaryButton} onClick={handleCTA}>
                    <div className={landingPageStyles.primaryButtonOverlay}></div>
                    <span className={landingPageStyles.primaryButtonContent} style={{ position: 'relative', zIndex: 10 }}>
                        Start Building
                        <ArrowRight className={landingPageStyles.primaryButtonIcon} size={16} />
                    </span>
                </button>
            </main>

            <footer className={landingPageStyles.footer}>
                <div className={landingPageStyles.footerContainer}>
                    <p className={landingPageStyles.footerText}>
                        Crafted with <span className={landingPageStyles.footerHeart}>❤️</span> by{' '}
                        <Link href="https://hexagondigitalservices.com/" target='_blank' className={landingPageStyles.footerLink}>
                            Hexagon Digital Services
                        </Link>
                    </p>
                </div>
            </footer>

            <Modal 
                isOpen={openAuthModel} 
                onClose={() => {
                    setOpenAuthModel(false);
                    setCurrentPage("login");
                }} 
                hideHeader
                title=""
                showActionBtn={false}
                actionBtnText=""
            >
                <div className="p-4">
                    {currentPage === "login" && (
                        <Login 
                            setCurrentPage={setCurrentPage} 
                            onSuccess={() => setOpenAuthModel(false)} // Pass this to close modal after login
                        />
                    )}
                    {currentPage === "signup" && (
                        <Signup 
                            setCurrentPage={setCurrentPage} 
                            onSuccess={() => setOpenAuthModel(false)} 
                        />
                    )}
                </div>
            </Modal> 
        </div>
    );
}

export default LandingPage;

import { NextRequest, NextResponse } from "next/server";
import crypto from "crypto";

import { db } from "@/src/db/index";
import { users } from "@/src/db/schema";
import { eq } from "drizzle-orm";

import { sendEmail } from "@/src/helpers/mailer";

export async function POST(request: NextRequest) {
  try {
    const reqBody = await request.json();
    const { email } = reqBody;

    // 1️⃣ Find user
    const user = await db
      .select()
      .from(users)
      .where(eq(users.email, email));

    if (user.length === 0) {
      return NextResponse.json(
        { error: "User does not exist" },
        { status: 400 }
      );
    }

    // 2️⃣ Send reset email
    await sendEmail({
      email,
      emailType: "RESET",
      userId: user[0].id,
    });

    return NextResponse.json({
      message: "Reset email sent successfully",
      success: true,
    });
  } catch (error: any) {
    return NextResponse.json(
      { error: error.message },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import { db } from "@/src/db";
import { users } from "@/src/db/schema";
import { getDataFromToken } from "@/src/helpers/getDataFromToken";
import { eq } from "drizzle-orm";

export async function GET(request: NextRequest) {
    try {
        // This replaces the 'protect' middleware
        const userId = await getDataFromToken(request);

        const user = await db.select()
            .from(users)
            .where(eq(users.id, userId));

        if (!user.length) {
            return NextResponse.json({ error: "User not found" }, { status: 404 });
        }

        // Don't send the password back!
        const { password, ...userData } = user[0];

        return NextResponse.json({
            message: "User found",
            data: userData
        });

    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 400 });
    }
}

"use client"
import { useState } from 'react'
// import { useNavigate } from 'react-router-dom'
import { useRouter } from 'next/navigation'
import { useUser } from '@/src/context/UserContext'
import { cardStyles } from '@/src/assets/dummystyle'
import { Award, Check, Clock, Edit, Trash2, TrendingUp, Zap } from 'lucide-react'

// PROFILE INFO CARDS

export const ProfileInCard = () => {
  const router = useRouter()
  // const { user, clearUser } = useContext(UserContext)
  const { user, clearUser, loading } = useUser()

  // if (!user) return null;
  // const context = useContext(UserContext);
  
  // if (!context) return null; 

  // const { user, clearUser } = context;

  const handleLogout = () => {
    localStorage.clear();
    clearUser();
    router.push('/')
  }

  if (loading || !user) return null;

  return (
    user && (
      <div className={cardStyles.profileCard}>
        <div className={cardStyles.profileInitialsContainer}>
          <span className={cardStyles.profileInitialsText}>
            {user.name ? user.name.charAt(0).toUpperCase() : ""}
          </span>
        </div>

        <div>
          <div className={cardStyles.profileName}>
            {user.name || ""}
          </div>
          <button className={cardStyles.logoutButton}
            onClick={handleLogout}>
            Logout
          </button>
        </div>
      </div>
    )
  )
}

//RESUME SUMMARY CARD 

export const ResumeSummaryCard = ({
  title = "Untitled Resume",
  imgUrl,
  createdAt = null,
  updatedAt = null,
  onSelect,
  onDelete,
  completion = 85,
}) => {
  const [isHovered, setIsHovered] = useState(false);

  const formattedCreatedDate = createdAt
    ? new Date(createdAt).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    })
    : "—";

  const formattedUpdatedDate = updatedAt
    ? new Date(updatedAt).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
      year: "numeric",
    })
    : "—";

  const getCompletionColor = () => {
    if (completion >= 90) return cardStyles.completionHigh;
    if (completion >= 70) return cardStyles.completionMedium;
    return cardStyles.completionLow;
  };

  const getCompletionIcon = () => {
    if (completion >= 90) return <Award size={12} />;
    if (completion >= 70) return <TrendingUp size={12} />;
    return <Zap size={12} />;
  };

  const handleDeleteClick = (e) => {
    e.stopPropagation();
    if (onDelete) onDelete();
  };

  const generateDesign = () => {
    const colors = [
      "from-blue-50 to-blue-100",
      "from-purple-50 to-purple-100",
      "from-emerald-50 to-emerald-100",
      "from-amber-50 to-amber-100",
      "from-rose-50 to-rose-100"
    ];
    return colors[title.length % colors.length];
  };

  const designColor = generateDesign();

  return (
    <div
      className={cardStyles.resumeCard}
      onClick={onSelect}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      {/* Completion indicator */}
      <div className={cardStyles.completionIndicator}>
        <div className={`${cardStyles.completionDot} bg-gradient-to-r ${getCompletionColor()}`}>
          <div className={cardStyles.completionDotInner} />
        </div>
        <span className={cardStyles.completionPercentageText}>{completion}%</span>
        {getCompletionIcon()}
      </div>

      {/* Preview area */}
      <div className={`${cardStyles.previewArea} bg-gradient-to-br ${designColor}`}>
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <div className={cardStyles.emptyPreviewIcon}>
            <Edit size={28} className="text-indigo-600" />
          </div>
          <span className={cardStyles.emptyPreviewText}>{title}</span>
          <span className={cardStyles.emptyPreviewSubtext}>
            {completion === 0 ? "Start building" : `${completion}% completed`}
          </span>

          {/* Mini resume sections indicator */}
          <div className="mt-4 flex gap-2">
            {['Profile', 'Work', 'Skills', 'Edu'].map((section, i) => (
              <div
                key={i}
                className={`px-2 py-1 text-xs rounded-md ${i < Math.floor(completion / 25)
                  ? 'bg-white/90 text-indigo-600 font-medium'
                  : 'bg-white/50 text-gray-500'
                  }`}
              >
                {section}
              </div>
            ))}
          </div>
        </div>

        {/* Hover overlay with action buttons */}
        {isHovered && (
          <div className={cardStyles.actionOverlay}>
            <div className={cardStyles.actionButtonsContainer}>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  if (onSelect) onSelect();
                }}
                className={cardStyles.editButton}
                title="Edit"
              >
                <Edit size={18} className={cardStyles.buttonIcon} />
              </button>
              <button
                onClick={handleDeleteClick}
                className={cardStyles.deleteButton}
                title="Delete"
              >
                <Trash2 size={18} className={cardStyles.buttonIcon} />
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Info area */}
      <div className={cardStyles.infoArea}>
        <div className="flex items-start justify-between mb-4">
          <div className="flex-1">
            <h5 className={cardStyles.title}>{title}</h5>
            <div className={cardStyles.dateInfo}>
              <Clock size={12} />
              <span>Created At: {formattedCreatedDate}</span>
              <span className="ml-2">Updated At: {formattedUpdatedDate}</span>
            </div>
          </div>
        </div>

        {/* Progress bar */}
        <div className="relative w-full h-2 bg-gray-200 rounded-full overflow-hidden">
          <div
            className={`h-full bg-gradient-to-r ${getCompletionColor()} rounded-full transition-all duration-700 ease-out relative overflow-hidden`}
            style={{ width: `${completion}%` }}
          >
            <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/30 to-transparent animate-pulse"></div>
          </div>
          <div
            className={`absolute top-0 h-full w-4 bg-gradient-to-r from-transparent to-white/50 blur-sm transition-all duration-700`}
            style={{ left: `${Math.max(0, completion - 2)}%` }}
          ></div>
        </div>

        {/* Completion status */}
        <div className="flex justify-between items-center mt-2">
          <span className="text-xs font-medium text-gray-500">
            {completion < 50 ? "Getting Started" : completion < 80 ? "Almost There" : "Ready to Go!"}
          </span>
          <span className="text-xs font-bold text-gray-700">{completion}% Complete</span>
        </div>
      </div>
    </div>
  );
};


// TEMPLATES CARD

export const TemplateCard = ({ thumbnailImg, isSelected, onSelect }) => {
  return (
    <div className={`group h-auto md:h-[300px] lg:h-[320px] flex flex-col bg-white border-2 overflow-hidden 
    cursor-pointer transition-all duration-500 hover:scale-105 hover:shadow-lg rounded-3xl
    ${isSelected 
        ? 'border-violet-500 shadow-lg shadow-violet-500/2 bg-violet-50'
        : 'border-gray-200 hover:border-violet-300'
      }`} onClick={onSelect}>
      {thumbnailImg ? (
        <div className='relative w-full h-full overflow-hidden'>
          <img src={thumbnailImg || 'placeholder.svg'} alt="Template Review" className='w-full h-full
          object-cover group-hover:scale-110 transition-transform duration-700'/>

          <div className='absolute inset-0 bg-gradient-to-t from-white/80 via-transparent
          to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300'/>

          {isSelected && (
            <div className='absolute inset-0 bg-violet-500/10 flex items-center justify-center'>
              <div className='w-16 h-16 bg-white backdrop-blur-sm rounded-full flex items-center
              justify-center shadow-lg animate-pulse'>
                <Check size={24} className="text-violet-600" />
              </div>
            </div>
          )}

          {/* HOVER EFFECT */}
          <div className='absolute inset-0 bg-gradient-to-t from-violet-100/30 to-transparent opacity-0
          group-hover:opacity-100 transition-opacity duration-300'>

          </div>

        </div>
      ) : (
        <div className='w-full h-[200px] flex items-center flex-col justify-center bg-gradient-to-br
        from-violet-50 via-violet-600 to-fuchsia-50'>
          <div className='w-12 h-12 bg-gradient-to-br from -violet-500 to-fuchsia-500 rounded-2xl flex
          items-center justify-center mb-3'>
            <Edit className='text-white' size={20} />
          </div>
          <span className='text-gray-700 font-bold'>
            No Preview
          </span>
        </div>
      )}

    </div>
  )
}

"use client"
import React, { useState } from 'react'
import { Input } from './Input'
// import { useNavigate } from 'react-router-dom'
import { useRouter } from 'next/navigation'
import axiosInstance from '@/src/utils/axiosInstance';
import { API_PATHS } from '@/src/utils/apiPaths'


const CreateResumeForm = ({onSuccess}) => {

  const [title, setTitle] = useState("");
  const [error, setError] = useState(null)
  // const navigate = useNavigate()
  const router = useRouter()

  const handleCreateResume = async(e) => {
    e.preventDefault();

    if(!title){
      setError("Please enter resume title")
      return
    }
    setError("")

    try{
      const response = await axiosInstance.post(API_PATHS.RESUME.CREATE, {
        title,
      })
      if(response.data?.id){
        router.push(`/editor/${response.data.id}`)
      }
    }
      catch(error){
        if(error.response && error.response.data.message){
          setError(error.response.data.message)
        }
        else {
          setError('Something went wrong. Please try again.')
        }
      }
  }

  return (

    
    <div className='w-full max-w-md p-8 bg-white rounded-2xl border border-gray-100 shadow-lg'>
        <h3 className='text-2xl font-bold text-gray-900 mb-2'>Create New Resume</h3>
        <p className='text-gray-600 mb-8'>
          Give your resume a title to get started. You can customize everything later.
        </p>

        <form onSubmit={handleCreateResume}>
            <Input value={title} onChange={({target}) => setTitle(target.value)}
            label='Resume Title' placeholder='e.g., John Doe -Software Engineer'
            type='text'/>

            {error && <p className='text-red-500 text-sm mb-4'>{error}</p>}

            <button type='submit' className='w-full py-3 bg-gradient-to-r from-rose-500 to-pink-600 text-white font-black
            rounded-2xl hover:scale-105 hover:shadow-xl hover:shadow-rose-200 transition-all'>
                Create Resume
            </button>
        </form>
    </div>
  )
}

export default CreateResumeForm

