"use client"; // Mandatory for Next.js Context

import React, { createContext, useState, useEffect, ReactNode, useContext } from "react";
import { API_PATHS } from "../utils/apiPaths";

// 1. Define the User Type (Adjust properties based on your backend)
interface User {
    id?: string;
    email: string;
    fullName?: string;
    token?: string;
}

// 2. Define the Context Interface
interface UserContextType {
    user: User | null;
    loading: boolean;
    updateUser: (userData: User) => void;
    clearUser: () => void;
}

// 3. Initialize with null but cast to the type to satisfy the ts(2554) error
export const UserContext = createContext<UserContextType | null>(null);

const UserProvider = ({ children }: { children: ReactNode }) => {
    const [user, setUser] = useState<User | null>(null);
    const [loading, setLoading] = useState(true);

    const clearUser = () => {
        setUser(null);
    };

    const fetchUser = async () => {
        try {
            const response = await fetch("/api/users/me", {
            method: "GET",
            headers: {
                "Content-Type": "application/json",
                // No need to manually send token, httpOnly cookie handles it
            },
        });

        if (!response.ok) {
            setUser(null);
            return;
        }

        const result = await response.json();
        setUser(result.data);
        } catch (error) {
            console.error("User not authenticated", error);
            clearUser();
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        // Next.js double-render check & localStorage availability
        if (typeof window !== "undefined") {
            fetchUser();
        }
    }, []);

    const updateUser = (userData: User) => {
        setUser(userData);
        setLoading(false);
    };

    return (
        <UserContext.Provider value={{ user, loading, updateUser, clearUser }}>
            {children}
        </UserContext.Provider>
    );
};



export default UserProvider;

export const useUser = () => {
    const context = useContext(UserContext);
    if (context === undefined || context === null) {
        // This "fake" object prevents the app from crashing 
        // while Next.js is still loading the actual context.
        return { 
            user: null, 
            loading: true, 
            updateUser: () => {}, 
            clearUser: () => {} 
        };
    }
    return context;
};

import nodemailer from "nodemailer";
import bcryptjs from "bcryptjs";

import { db } from "@/src/db/index";
import { users } from "@/src/db/schema";
import { eq } from "drizzle-orm";
import { configDotenv } from "dotenv";

import crypto from "crypto";

type EmailParams = {
  email: string;
  emailType: "VERIFY" | "RESET";
  userId: number;
};

export const sendEmail = async ({
  email,
  emailType,
  userId,
}: EmailParams) => {
  try {

    console.log("HOST:", process.env.MAILTRAP_HOST);
    console.log("PORT:", process.env.MAILTRAP_PORT);
    console.log("USER:", process.env.MAILTRAP_USER);
    console.log("PASS:", process.env.MAILTRAP_PASS);

    // create a secure, URL-safe hexadecimal token
    const hashedToken = crypto.randomBytes(32).toString('hex');

    if (emailType === "VERIFY") {
      await db
        .update(users)
        .set({
          verifyToken: hashedToken,
          verifyTokenExpiry: new Date(Date.now() + 3600000),
        })
        .where(eq(users.id, userId));
    } else if (emailType === "RESET") {
      await db
        .update(users)
        .set({
          forgotPasswordToken: hashedToken,
          forgotPasswordTokenExpiry: new Date(
            Date.now() + 3600000
          ),
        })
        .where(eq(users.id, userId));
    }

    const transport = nodemailer.createTransport({
      host: process.env.MAILTRAP_HOST,
      port: Number(process.env.MAILTRAP_PORT) || 2525,
      auth: {
        user: process.env.MAILTRAP_USER,
        pass: process.env.MAILTRAP_PASS,
      },
    });

     const link =
      emailType === "VERIFY"
        ? `${process.env.DOMAIN}/verifyemail?token=${hashedToken}`
        : `${process.env.DOMAIN}/resetpassword?token=${hashedToken}`;

    const mailOptions = {
      from: "nehakeshri@gmail.com",
      to: email,
      subject:
        emailType === "VERIFY"
          ? "Verify your email"
          : "Reset your password",

      html: `
        <p>
        Click the link below to ${
          emailType === "VERIFY"
            ? "verify your email"
            : "reset your password"
        }
        </p>

        <a href="${link}">
        Click Here
        </a>
         <p>If the link doesn't work copy this:</p>
        <p>${link}</p>
      `,
    };

    const mailResponse = await transport.sendMail(mailOptions);

    return mailResponse;
  } catch (error: any) {
    console.error("Email sending error:", error);
    throw new Error(error.message);
  }
};

// src/utils/colors.js
import Color from 'colorjs.io'; // Standard library for color conversion

export const fixTailwindColors = (element) => {
  const clone = element.cloneNode(true);
  clone.style.position = 'absolute';
  clone.style.left = '-9999px';
  clone.style.width = `${element.offsetWidth}px`;
  document.body.appendChild(clone);

  const convertToRgb = (colorValue) => {
    if (!colorValue || !colorValue.includes('oklch')) return colorValue;
    try {
      // Use a real library to convert the space
      const c = new Color(colorValue);
      return c.to('srgb').toString({ format: 'rgb' });
    } catch (e) {
      // Fallback to a safe color if conversion fails
      return 'rgb(0, 0, 0)'; 
    }
  };

  const allElements = [clone, ...clone.querySelectorAll('*')];
  
  allElements.forEach(el => {
    const computed = window.getComputedStyle(el);
    
    // Check and fix the three main color properties
    const props = ['backgroundColor', 'color', 'borderColor'];
    props.forEach(prop => {
      if (computed[prop].includes('oklch')) {
        el.style[prop] = convertToRgb(computed[prop]);
      }
    });
  });

  // IMPORTANT: Remember to remove this clone after the PDF is generated!
  // You should handle the removal in the calling function: clone.remove();
  
  return clone;
};
